    /// Dock InitialPayload TankHunter × 2 into a Listening Outpost residual.
    ///
    /// Fail-closed: no dock when TankHunter template is missing or capacity full.
    fn apply_listening_outpost_initial_payload(
        &mut self,
        outpost_id: ObjectId,
        team: Team,
        position: Vec3,
    ) {
        use crate::game_logic::host_listening_outpost::{
            preferred_payload_template, tank_hunter_missile_weapon,
            LISTENING_OUTPOST_INITIAL_PAYLOAD_COUNT, LISTENING_OUTPOST_PAYLOAD_TEMPLATE,
            LISTENING_OUTPOST_PAYLOAD_TEMPLATE_ALT,
        };

        // Ensure a payload template is available (retail or host seed).
        if !self
            .templates
            .contains_key(LISTENING_OUTPOST_PAYLOAD_TEMPLATE)
            && !self
                .templates
                .contains_key(LISTENING_OUTPOST_PAYLOAD_TEMPLATE_ALT)
        {
            // Inject residual TankHunter template for host playability residual.
            let mut th = ThingTemplate::new(LISTENING_OUTPOST_PAYLOAD_TEMPLATE_ALT);
            th.add_kind_of(KindOf::Infantry)
                .add_kind_of(KindOf::Selectable)
                .add_kind_of(KindOf::Attackable)
                .set_health(70.0)
                .set_cost(110, 0);
            self.templates
                .insert(LISTENING_OUTPOST_PAYLOAD_TEMPLATE_ALT.to_string(), th);
        }

        let payload_name = preferred_payload_template(
            self.templates
                .contains_key(LISTENING_OUTPOST_PAYLOAD_TEMPLATE),
            self.templates
                .contains_key(LISTENING_OUTPOST_PAYLOAD_TEMPLATE_ALT),
        );
        let Some(payload_name) = payload_name else {
            return;
        };

        for _ in 0..LISTENING_OUTPOST_INITIAL_PAYLOAD_COUNT {
            // Capacity check before spawn (avoid orphan infantry on full residual).
            let has_space = self
                .objects
                .get(&outpost_id)
                .map(|o| o.has_capacity_for(1))
                .unwrap_or(false);
            if !has_space {
                break;
            }

            let Some(hunter_id) = self.create_object(payload_name, team, position) else {
                break;
            };

            // Ensure TankHunter residual missile weapon for armed-riders residual.
            if let Some(hunter) = self.objects.get_mut(&hunter_id) {
                if hunter.weapon.is_none()
                    || hunter
                        .weapon
                        .as_ref()
                        .map(|w| w.damage < 1.0)
                        .unwrap_or(true)
                {
                    hunter.weapon = Some(tank_hunter_missile_weapon());
                }
                hunter.contained_by = Some(outpost_id);
                hunter.ai_state = AIState::Docked;
                hunter.stop_moving();
                hunter.status.moving = false;
                hunter.status.attacking = false;
                hunter.set_target(None);
                hunter.set_position(position);
            }

            if let Some(outpost) = self.objects.get_mut(&outpost_id) {
                outpost.add_occupant(hunter_id);
            }
            self.listening_outpost.record_initial_payload_dock();
        }

        self.refresh_battle_bus_armed_riders_weapon_set(outpost_id);
    }

    /// Dock InitialPayload Redguard × 8 into a Troop Crawler residual.
    ///
    /// Fail-closed: injects host seed RedGuard template when retail name missing.
    fn apply_troop_crawler_initial_payload(
        &mut self,
        crawler_id: ObjectId,
        team: Team,
        position: Vec3,
    ) {
        use crate::game_logic::host_troop_crawler::{
            resolve_payload_template_name, TROOP_CRAWLER_INITIAL_PAYLOAD_COUNT,
            TROOP_CRAWLER_PAYLOAD_TEMPLATE, TROOP_CRAWLER_PAYLOAD_TEMPLATE_ALIAS,
        };
        use crate::game_logic::weapon_bootstrap::REDGUARD_PRIMARY_WEAPON;

        // Ensure a payload template is available (retail or host seed).
        if !self.templates.contains_key(TROOP_CRAWLER_PAYLOAD_TEMPLATE)
            && !self
                .templates
                .contains_key(TROOP_CRAWLER_PAYLOAD_TEMPLATE_ALIAS)
            && !self.templates.contains_key("TestInfantry")
        {
            let mut rg = ThingTemplate::new(TROOP_CRAWLER_PAYLOAD_TEMPLATE_ALIAS);
            rg.add_kind_of(KindOf::Infantry)
                .add_kind_of(KindOf::Selectable)
                .add_kind_of(KindOf::Attackable)
                .set_health(55.0)
                .set_cost(70, 0)
                .set_primary_weapon_name(REDGUARD_PRIMARY_WEAPON);
            self.templates
                .insert(TROOP_CRAWLER_PAYLOAD_TEMPLATE_ALIAS.to_string(), rg);
        }

        let payload_name = resolve_payload_template_name(|n| self.templates.contains_key(n));
        let Some(payload_name) = payload_name else {
            return;
        };

        for i in 0..TROOP_CRAWLER_INITIAL_PAYLOAD_COUNT {
            let has_space = self
                .objects
                .get(&crawler_id)
                .map(|o| o.has_capacity_for(1))
                .unwrap_or(false);
            if !has_space {
                break;
            }

            let Some(guard_id) = self.create_object(payload_name, team, position) else {
                break;
            };

            if let Some(guard) = self.objects.get_mut(&guard_id) {
                // Ensure residual combat weapon so assault-deploy attack residual works.
                if guard.weapon.is_none() {
                    guard.weapon = Some(Weapon {
                        damage: 15.0,
                        range: 100.0,
                        reload_time: 1.0,
                        last_fire_time: 0.0,
                        ..Weapon::default()
                    });
                }
                guard.contained_by = Some(crawler_id);
                guard.ai_state = AIState::Docked;
                guard.stop_moving();
                guard.status.moving = false;
                guard.status.attacking = false;
                guard.set_target(None);
                guard.set_position(position);
            }

            if let Some(crawler) = self.objects.get_mut(&crawler_id) {
                crawler.add_occupant(guard_id);
            }
            self.troop_crawler.record_initial_payload();
            // Initial payload docks count as residual loads for honesty bookkeeping.
            let _ = i;
        }
    }

    /// Residual Troop Crawler assault deploy: unload docked infantry and order attack.
    ///
    /// C++ AssaultTransportAIUpdate::beginAssault + update exit/attack residual.
    /// Fail-closed: not wounded-retrieve / multi-exit stagger / heal matrix.
    fn apply_troop_crawler_assault_deploy(
        &mut self,
        crawler_id: ObjectId,
        target_id: ObjectId,
    ) -> u32 {
        use crate::game_logic::host_troop_crawler::TROOP_CRAWLER_DEPLOY_AUDIO;

        let Some(crawler) = self.objects.get(&crawler_id) else {
            return 0;
        };
        if !crawler.is_troop_crawler_style_container() {
            return 0;
        }
        let crawler_pos = crawler.get_position();
        let occupants = crawler.contained_units();
        if occupants.is_empty() {
            // Still record deploy attempt residual (weapon fired DEPLOY pulse).
            self.troop_crawler.record_assault_deploy();
            return 0;
        }

        let mut ordered = 0u32;
        for (i, occ_id) in occupants.iter().copied().enumerate() {
            // Remove from container.
            if let Some(crawler) = self.objects.get_mut(&crawler_id) {
                crawler.remove_occupant(occ_id);
            }
            // Drop near crawler and order attack.
            let angle = (occ_id.0 as f32 + i as f32 * 1.37).sin().atan2(1.0) + i as f32 * 0.7;
            let offset = Vec3::new(angle.cos(), 0.0, angle.sin()) * 8.0;
            if let Some(unit) = self.objects.get_mut(&occ_id) {
                unit.stop_moving();
                unit.set_position(crawler_pos + offset);
                unit.contained_by = None;
                unit.status.moving = false;
                // GoAggressiveOnExit residual: attack designated target.
                unit.attack_target(target_id);
                ordered = ordered.saturating_add(1);
                self.troop_crawler.record_deploy_attack_order();
                self.troop_crawler.record_unload();
            }
        }

        self.troop_crawler.record_assault_deploy();
        self.queue_audio_event(
            AudioEventRequest::new(TROOP_CRAWLER_DEPLOY_AUDIO)
                .with_object(crawler_id)
                .with_position(crawler_pos)
                .with_priority(140),
        );
        ordered
    }

    /// Record a residual Overlord BattleBunker enter (tests / host path).
    pub fn record_overlord_bunker_residual_enter(&mut self) {
        self.overlord_bunker_residual_enters =
            self.overlord_bunker_residual_enters.saturating_add(1);
    }

    /// Record a residual Overlord BattleBunker exit/evacuate (tests / host path).
    pub fn record_overlord_bunker_residual_exit(&mut self) {
        self.overlord_bunker_residual_exits = self.overlord_bunker_residual_exits.saturating_add(1);
    }

    /// Residual base-defense auto-fire: Patriot / Gattling / FSBaseDefense
    /// structures acquire nearest enemy in weapon range and deal damage without
    /// a manual AttackObject order.
    ///
    /// China Gattling Cannon residual adds:
    /// - dual-slot air/ground chooser (`GattlingBuildingGun` / `GunAir`)
    /// - continuous-fire ramp (One=1 / Two=5 / Coast=2000ms)
    /// - Chain Guns PLAYER_UPGRADE damage × 1.25
    ///
    /// Fail-closed: not full AutoAcquire LOS / turret pitch / CONTINUOUS_FIRE anim.
    fn try_base_defense_residual_fire(&mut self, defense_id: ObjectId) {
        use crate::game_logic::host_base_defense::{
            is_dual_slot_base_defense, is_gattling_cannon_structure, is_patriot_battery_structure,
            is_stinger_site_structure, preferred_dual_defense_slot, GATTLING_BUILDING_FIRE_AUDIO,
            PATRIOT_FIRE_AUDIO, STINGER_FIRE_AUDIO,
        };

        let current_time = self.frame as f32 * LOGIC_FRAME_TIMESTEP;

        let Some(attacker) = self.objects.get(&defense_id) else {
            return;
        };
        if !attacker.is_alive()
            || !attacker.is_constructed()
            || attacker.weapon.is_none()
            || !attacker.can_attack()
        {
            return;
        }
        let template_name = attacker.template_name.clone();
        let is_gattling = is_gattling_cannon_structure(&template_name);
        let is_stinger = is_stinger_site_structure(&template_name);
        let is_patriot = is_patriot_battery_structure(&template_name);
        let dual_slot = is_dual_slot_base_defense(&template_name);
        let team = attacker.team;
        let fire_pos = attacker.get_position();
        let ground_range = attacker.weapon.as_ref().map(|w| w.range).unwrap_or(0.0);
        let air_range = attacker
            .secondary_weapon
            .as_ref()
            .map(|w| w.range)
            .unwrap_or(0.0);
        // Scan range residual: dual-slot defenses use max(primary, secondary) so AA
        // can acquire out to air range while ground stays at primary range.
        let scan_range = if dual_slot {
            ground_range.max(air_range)
        } else {
            ground_range
        };
        if scan_range <= 0.0 {
            return;
        }

        let mut best: Option<(ObjectId, f32, bool)> = None;
        for (id, obj) in &self.objects {
            if *id == defense_id {
                continue;
            }
            let combat_kind = obj.is_kind_of(KindOf::Attackable)
                || obj.is_kind_of(KindOf::Structure)
                || obj.is_kind_of(KindOf::Infantry)
                || obj.is_kind_of(KindOf::Vehicle)
                || obj.is_kind_of(KindOf::Aircraft);
            if !crate::game_logic::host_base_defense::is_legal_base_defense_target(
                obj.is_alive(),
                obj.team == team,
                obj.team == Team::Neutral,
                obj.status.under_construction,
                combat_kind,
            ) {
                continue;
            }
            // Stealthed + undetected residual: skip (parity with update_combat).
            if obj.is_effectively_stealthed() && obj.team != team {
                continue;
            }
            let is_air = obj.is_kind_of(KindOf::Aircraft) || obj.status.airborne_target;
            let dist = fire_pos.distance(obj.get_position());
            let in_range = if dual_slot {
                if is_air {
                    dist <= air_range.max(ground_range)
                } else {
                    dist <= ground_range
                }
            } else {
                dist <= scan_range
            };
            if in_range && best.map(|(_, d, _)| dist < d).unwrap_or(true) {
                best = Some((*id, dist, is_air));
            }
        }

        let Some((target_id, _, target_is_air)) = best else {
            return;
        };

        let slot = if dual_slot {
            preferred_dual_defense_slot(target_is_air)
        } else {
            0
        };

        // Readiness residual: use the slot that will fire.
        let ready = {
            let Some(attacker) = self.objects.get(&defense_id) else {
                return;
            };
            if slot == 1 {
                attacker
                    .secondary_weapon
                    .as_ref()
                    .is_some_and(|w| Object::weapon_ready(w, current_time))
            } else {
                attacker
                    .weapon
                    .as_ref()
                    .is_some_and(|w| Object::weapon_ready(w, current_time))
            }
        };
        if !ready {
            return;
        }

        let damage = {
            let Some(attacker) = self.objects.get(&defense_id) else {
                return;
            };
            if slot == 1 {
                attacker
                    .secondary_weapon
                    .as_ref()
                    .map(|w| w.damage)
                    .unwrap_or(0.0)
            } else {
                attacker.weapon.as_ref().map(|w| w.damage).unwrap_or(0.0)
            }
        };
        if damage <= 0.0 {
            return;
        }

        // America Fire Base residual: dual-radius howitzer splash owns damage.
        // Fail-closed: not full ScatterRadiusVsInfantry / ScaleWeaponSpeed lob matrix.
        let is_fire_base =
            crate::game_logic::host_fire_base::is_fire_base_template(&template_name);
        let mut destroyed = false;
        let mut kill_xp = 0.0;
        if is_fire_base {
            let impact = self
                .objects
                .get(&target_id)
                .map(|t| t.get_position())
                .unwrap_or(fire_pos);
            let (hits, any_destroyed) =
                self.apply_fire_base_residual_at(impact, Some(defense_id), Some(target_id));
            destroyed = any_destroyed;
            if destroyed {
                if let Some(target) = self.objects.get(&target_id) {
                    kill_xp = target.thing.template.experience_value
                        * Self::veterancy_xp_multiplier(target.experience.level);
                }
            }
            let _ = hits;
        } else if let Some(target) = self.objects.get_mut(&target_id) {
            destroyed = target.take_damage(damage);
            if destroyed {
                kill_xp = target.thing.template.experience_value
                    * Self::veterancy_xp_multiplier(target.experience.level);
            }
        }

        if let Some(attacker) = self.objects.get_mut(&defense_id) {
            if slot == 1 {
                if let Some(w) = attacker.secondary_weapon.as_mut() {
                    w.last_fire_time = current_time;
                }
            } else if let Some(w) = attacker.weapon.as_mut() {
                w.last_fire_time = current_time;
            }
            // Track engagement for UI / subsequent frames without requiring
            // a player AttackObject. Structures stay immobile (no chase).
            attacker.target = Some(target_id);
            attacker.target_location = None;
            attacker.force_attack = false;
            attacker.ai_state = AIState::Attacking;
            attacker.status.attacking = true;
            if destroyed {
                attacker.gain_experience(kill_xp);
                attacker.stop_attack();
            }
        }

        if destroyed && !is_fire_base {
            // Fire Base residual already mark_object_for_destruction inside apply.
            self.mark_object_for_destruction(target_id, Some(team));
        }

        // Continuous-fire ramp residual for structure gattling.
        if is_gattling {
            self.advance_gattling_building_continuous_fire(defense_id, Some(target_id), slot);
        }

        // Muzzle + audio residual (shared combat honesty).
        let muzzle_pos = self
            .objects
            .get(&defense_id)
            .map(|a| a.get_position())
            .unwrap_or(fire_pos);
        let impact_pos = self.objects.get(&target_id).map(|t| t.get_position());
        let _ = self.combat_particles.spawn_weapon_fire_fx(
            muzzle_pos,
            impact_pos,
            self.frame,
            defense_id,
            Some(target_id),
        );
        let is_tunnel =
            crate::game_logic::host_tunnel_network::is_tunnel_network_template(&template_name);
        let is_laser_patriot =
            crate::game_logic::host_base_defense::is_laser_patriot_template(&template_name);
        let audio = if is_gattling {
            GATTLING_BUILDING_FIRE_AUDIO
        } else if is_stinger {
            STINGER_FIRE_AUDIO
        } else if is_patriot && is_laser_patriot {
            crate::game_logic::host_base_defense::LAZR_PATRIOT_FIRE_AUDIO
        } else if is_patriot {
            PATRIOT_FIRE_AUDIO
        } else if is_fire_base {
            crate::game_logic::host_fire_base::FIRE_BASE_FIRE_AUDIO
        } else if is_tunnel {
            crate::game_logic::host_tunnel_network::TUNNEL_NETWORK_GUN_AUDIO
        } else {
            "WeaponFire"
        };
        self.queue_audio_event(
            AudioEventRequest::new(audio)
                .with_object(defense_id)
                .with_position(muzzle_pos)
                .with_priority(160),
        );

        self.base_defense_residual_fires = self.base_defense_residual_fires.saturating_add(1);

        // Per-structure residual honesty counters.
        if is_stinger {
            if slot == 1 {
                self.stinger_site_residual_aa_fires =
                    self.stinger_site_residual_aa_fires.saturating_add(1);
            } else {
                self.stinger_site_residual_ground_fires =
                    self.stinger_site_residual_ground_fires.saturating_add(1);
            }
        }
        if is_patriot {
            if slot == 1 {
                self.patriot_residual_aa_fires = self.patriot_residual_aa_fires.saturating_add(1);
            } else {
                self.patriot_residual_ground_fires =
                    self.patriot_residual_ground_fires.saturating_add(1);
            }
            // Superweapon General EMP Patriot residual: EMPPatriotEffectSpheroid on impact.
            // Fail-closed: not full OCL spheroid drawable / assist clip matrix.
            if crate::game_logic::host_base_defense::is_supw_patriot_template(&template_name) {
                self.apply_supw_patriot_emp_residual_at(
                    impact_pos.unwrap_or(fire_pos),
                    defense_id,
                    team,
                );
            }
        }
        if is_tunnel {
            // TunnelNetworkGun residual honesty (base-defense auto-fire path).
            self.tunnel_network.record_gun_fire(true);
        }
    }

    /// SupW Patriot EMP residual: DISABLED_EMP for legal victims in EffectRadius 10.
    ///
    /// Retail EMPPatriotEffectSpheroid EMPUpdate residual (DisabledDuration 10000 ms).
    /// DoesNotAffectMyOwnBuildings residual skips own faction structures.
    fn apply_supw_patriot_emp_residual_at(
        &mut self,
        impact: glam::Vec3,
        source_id: ObjectId,
        source_team: Team,
    ) {
        use crate::game_logic::host_base_defense::{
            is_legal_supw_patriot_emp_target, supw_patriot_emp_until_frame, SUPW_PATRIOT_EMP_AUDIO,
            SUPW_PATRIOT_EMP_RADIUS,
        };
        use crate::game_logic::host_emp_pulse::is_emp_hardened_name;

        let until = supw_patriot_emp_until_frame(self.frame);
        let radius = SUPW_PATRIOT_EMP_RADIUS;
        let victims: Vec<ObjectId> = self
            .objects
            .iter()
            .filter_map(|(id, obj)| {
                if *id == source_id || !obj.is_alive() {
                    return None;
                }
                let dx = obj.get_position().x - impact.x;
                let dz = obj.get_position().z - impact.z;
                if (dx * dx + dz * dz).sqrt() > radius {
                    return None;
                }
                let is_vehicle = obj.is_kind_of(KindOf::Vehicle);
                let is_aircraft =
                    obj.is_kind_of(KindOf::Aircraft) || obj.status.airborne_target;
                let is_structure = obj.is_kind_of(KindOf::Structure);
                let is_own_structure = is_structure && obj.team == source_team;
                let is_faction_structure = is_structure
                    && (obj.team == Team::USA
                        || obj.team == Team::China
                        || obj.team == Team::GLA);
                if !is_legal_supw_patriot_emp_target(
                    is_vehicle,
                    is_aircraft,
                    is_faction_structure,
                    is_own_structure,
                    true,
                    obj.status.under_construction,
                    is_emp_hardened_name(&obj.template_name),
                ) {
                    return None;
                }
                Some(*id)
            })
            .collect();
        let mut any = false;
        for vid in victims {
            if let Some(v) = self.objects.get_mut(&vid) {
                v.apply_disabled_emp(until);
                any = true;
            }
        }
        if any {
            self.supw_patriot_emp_residual_grants =
                self.supw_patriot_emp_residual_grants.saturating_add(1);
            self.queue_audio_event(
                AudioEventRequest::new(SUPW_PATRIOT_EMP_AUDIO)
                    .with_object(source_id)
                    .with_position(impact)
                    .with_priority(165),
            );
        }
    }

    /// Residual honesty: at least one base-defense auto-fire residual shot.
    pub fn honesty_base_defense_fire_ok(&self) -> bool {
        self.base_defense_residual_fires > 0
    }

    /// Residual honesty counter: base-defense auto-fire residual shots.
    pub fn base_defense_residual_fires(&self) -> u32 {
        self.base_defense_residual_fires
    }

    /// Host PointDefenseLaser residual: Paladin / Avenger destroy nearest
    /// interceptable missile/projectile (primary) or damage infantry (secondary)
    /// in residual fire range without a manual AttackObject order.
    ///
    /// Fail-closed: not full PointDefenseLaserUpdate velocity prediction,
    /// TERTIARY WeaponStore allocate, or laser drawable path.
    pub fn update_point_defense_intercept(&mut self) {
        use crate::game_logic::host_point_defense::{
            in_pdl_range_2d, intercept_priority, is_point_defense_carrier,
            is_primary_intercept_target, is_secondary_intercept_target, pdl_damage,
            pdl_delay_frames, pdl_fire_range, PDL_INTERCEPT_AUDIO,
        };

        // Snapshot carriers first (immutable pass).
        let carriers: Vec<(ObjectId, String, Team, glam::Vec3)> = self
            .objects
            .iter()
            .filter_map(|(id, obj)| {
                // C++ PointDefenseLaserUpdate is independent of primary WeaponSet:
                // only requires carrier alive / not effectively dead / not disabled.
                if !obj.is_alive() || obj.is_disabled() {
                    return None;
                }
                if !is_point_defense_carrier(&obj.template_name) {
                    return None;
                }
                // Under construction / unmanned residual: no laser.
                if obj.status.under_construction || obj.status.disabled_unmanned {
                    return None;
                }
                // Weapons jam residual: cannot fire laser either.
                if obj.status.weapons_jammed {
                    return None;
                }
                Some((*id, obj.template_name.clone(), obj.team, obj.get_position()))
            })
            .collect();

        if carriers.is_empty() {
            return;
        }

        let frame = self.frame;
        let mut intercepts_this_pass = 0u32;

        for (carrier_id, template_name, team, carrier_pos) in carriers {
            let ready_frame = self
                .point_defense_next_ready_frame
                .get(&carrier_id)
                .copied()
                .unwrap_or(0);
            if frame < ready_frame {
                continue;
            }

            let fire_range = pdl_fire_range(&template_name);
            let damage = pdl_damage(&template_name);
            let delay = pdl_delay_frames(&template_name);
            let carrier_xz = (carrier_pos.x, carrier_pos.z);

            // Find best target: primary missiles first, then secondary infantry.
            // Prefer closer targets within same priority band.
            let mut best: Option<(ObjectId, u8, f32)> = None;
            for (tid, target) in &self.objects {
                if *tid == carrier_id || !target.is_alive() {
                    continue;
                }
                let same_team = target.team == team;
                let is_primary = is_primary_intercept_target(
                    target.is_kind_of(KindOf::Projectile)
                        || target.object_type == ObjectType::Projectile,
                    target.is_alive(),
                    same_team,
                    &target.template_name,
                );
                // Retail: only Paladin has SecondaryTargetTypes = INFANTRY.
                // Avenger / King Raptor / Combat Chinook: missiles only.
                let is_secondary = if crate::game_logic::host_usa_tanks::paladin_allows_secondary_infantry_intercept(
                    &template_name,
                ) {
                    is_secondary_intercept_target(
                        target.is_kind_of(KindOf::Infantry),
                        target.is_alive(),
                        same_team,
                        target.status.under_construction,
                    )
                } else {
                    false
                };
                let Some(prio) = intercept_priority(is_primary, is_secondary) else {
                    continue;
                };
                let tpos = target.get_position();
                if !in_pdl_range_2d(carrier_xz, (tpos.x, tpos.z), fire_range) {
                    continue;
                }
                let dist = carrier_pos.distance(tpos);
                let better = match best {
                    None => true,
                    Some((_, bp, bd)) => prio < bp || (prio == bp && dist < bd),
                };
                if better {
                    best = Some((*tid, prio, dist));
                }
            }

            let Some((target_id, prio, _)) = best else {
                continue;
            };

            // Primary missiles / projectiles: destroy residual (laser one-shots).
            // Secondary infantry: apply PDL damage residual.
            let mut destroyed = false;
            let mut impact_pos = carrier_pos;
            if prio == 0 {
                if let Some(target) = self.objects.get_mut(&target_id) {
                    impact_pos = target.get_position();
                    // Instant destroy residual for interceptable missiles.
                    let _ = target.take_damage(target.health.current.max(damage));
                    destroyed = !target.is_alive() || target.health.current <= 0.0;
                    if !destroyed {
                        // Force kill residual if armor residual blocked full clear.
                        destroyed = target.take_damage(damage * 10.0);
                    }
                }
            } else if let Some(target) = self.objects.get_mut(&target_id) {
                impact_pos = target.get_position();
                destroyed = target.take_damage(damage);
            }

            self.point_defense_next_ready_frame
                .insert(carrier_id, frame.saturating_add(delay));
            intercepts_this_pass = intercepts_this_pass.saturating_add(1);
            self.point_defense_residual_intercepts =
                self.point_defense_residual_intercepts.saturating_add(1);

            if destroyed {
                self.mark_object_for_destruction(target_id, Some(team));
            }

            let _ = self.combat_particles.spawn_weapon_fire_fx(
                carrier_pos,
                Some(impact_pos),
                frame,
                carrier_id,
                Some(target_id),
            );
            self.queue_audio_event(
                AudioEventRequest::new(PDL_INTERCEPT_AUDIO)
                    .with_object(carrier_id)
                    .with_position(carrier_pos)
                    .with_priority(150),
            );
        }

        if intercepts_this_pass > 0 {
            log::debug!(
                "PointDefenseLaser residual: {} intercept(s) this pass (total={})",
                intercepts_this_pass,
                self.point_defense_residual_intercepts
            );
        }
    }

