    /// Host Aurora dive-bomb residual registry (queue + honesty).
    pub fn aurora_bombs(&self) -> &crate::game_logic::host_aurora_bomb::HostAuroraBombRegistry {
        &self.aurora_bombs
    }

    /// Residual honesty: at least one Aurora bomb dive activated/queued.
