    /// Residual: Upgrade_AmericaBunkerBusters tags Stealth Fighter + combat kills
    /// garrisoned occupants and amplifies bunker structure damage.
    #[test]
    fn bunker_buster_residual_kills_garrison_and_damages_bunker() {
        use crate::command_system::{CommandType, GameCommand};
        use crate::game_logic::host_bunker_buster::{
            is_bunker_buster_carrier, UPGRADE_AMERICA_BUNKER_BUSTERS,
        };
        use crate::game_logic::host_upgrades::HostUpgradeKind;
        use crate::game_logic::weapon_bootstrap::{
            ensure_host_weapon_store, STEALTH_JET_MISSILE_WEAPON,
        };

        ensure_host_weapon_store();

        let mut game_logic = GameLogic::new();
        let mut player = Player::new(0, Team::USA, "USA", true);
        player.resources.supplies = 10_000;
        game_logic.add_player(player);
        ensure_test_infantry_template(&mut game_logic);
        ensure_test_garrison_template(&mut game_logic);
        ensure_test_barracks_template(&mut game_logic);

        let mut fighter_tpl = crate::game_logic::ThingTemplate::new("AmericaJetStealthFighter");
        fighter_tpl
            .add_kind_of(KindOf::Aircraft)
            .add_kind_of(KindOf::Vehicle)
            .add_kind_of(KindOf::Selectable)
            .add_kind_of(KindOf::Attackable)
            .set_health(160.0)
            .set_primary_weapon_name(STEALTH_JET_MISSILE_WEAPON);
        game_logic
            .templates
            .insert("AmericaJetStealthFighter".to_string(), fighter_tpl);

        let airfield_id = game_logic
            .create_object("TestBarracks", Team::USA, Vec3::new(-50.0, 0.0, 0.0))
            .expect("producer");

        let fighter_id = game_logic
            .create_object(
                "AmericaJetStealthFighter",
                Team::USA,
                Vec3::new(0.0, 0.0, 0.0),
            )
            .expect("stealth fighter");
        {
            let f = game_logic.find_object(fighter_id).expect("fighter");
            assert!(is_bunker_buster_carrier(&f.template_name));
            assert!(
                !f.has_upgrade_tag(UPGRADE_AMERICA_BUNKER_BUSTERS),
                "pre-upgrade fighter must lack bunker-buster tag"
            );
        }

        // Enemy bunker with two garrisoned infantry.
        let bunker_id = game_logic
            .create_object("TestBunker", Team::GLA, Vec3::new(80.0, 0.0, 0.0))
            .expect("bunker");
        let inf_a = game_logic
            .create_object("TestInfantry", Team::GLA, Vec3::new(81.0, 0.0, 0.0))
            .expect("inf_a");
        let inf_b = game_logic
            .create_object("TestInfantry", Team::GLA, Vec3::new(82.0, 0.0, 0.0))
            .expect("inf_b");
        {
            let bunker = game_logic.find_object_mut(bunker_id).unwrap();
            assert!(bunker.add_occupant(inf_a));
            assert!(bunker.add_occupant(inf_b));
        }
        for id in [inf_a, inf_b] {
            let u = game_logic.find_object_mut(id).unwrap();
            u.contained_by = Some(bunker_id);
            u.ai_state = AIState::Garrisoned;
            u.set_position(Vec3::new(80.0, 0.0, 0.0));
        }

        let bunker_hp_before = game_logic
            .find_object(bunker_id)
            .map(|b| b.health.current)
            .unwrap_or(0.0);

        // Research bunker busters.
        game_logic.queue_command(GameCommand {
            command_type: CommandType::QueueUpgrade {
                upgrade_name: UPGRADE_AMERICA_BUNKER_BUSTERS.to_string(),
            },
            player_id: 0,
            command_id: 1,
            timestamp: std::time::SystemTime::now(),
            selected_units: vec![airfield_id],
            modifier_keys: crate::command_system::ModifierKeys::default(),
        });
        game_logic.process_commands();
        assert!(
            game_logic
                .host_upgrades()
                .honesty_queue_ok(HostUpgradeKind::BunkerBusters),
            "bunker busters upgrade must queue residual"
        );
        game_logic.update();
        assert!(
            game_logic
                .host_upgrades()
                .honesty_complete_ok(HostUpgradeKind::BunkerBusters),
            "bunker busters upgrade must complete residual"
        );
        {
            let f = game_logic.find_object(fighter_id).expect("fighter");
            assert!(
                f.has_upgrade_tag(UPGRADE_AMERICA_BUNKER_BUSTERS),
                "stealth fighter must receive bunker-buster upgrade tag"
            );
        }

        // Fire residual missile at bunker.
        {
            let f = game_logic.find_object_mut(fighter_id).unwrap();
            f.attack_target(bunker_id);
            if let Some(w) = f.weapon.as_mut() {
                w.last_fire_time = -10.0;
                w.reload_time = 0.1;
                w.min_range = 0.0;
                w.damage = 100.0; // StealthJetMissile residual
            }
            f.set_position(Vec3::new(50.0, 0.0, 0.0));
        }

        game_logic.set_current_frame(30);
        game_logic.update_combat(&[fighter_id, bunker_id, inf_a, inf_b], LOGIC_FRAME_TIMESTEP);

        assert!(
            game_logic.honesty_bunker_buster_ok(),
            "bunker-buster residual honesty host path"
        );
        assert!(
            game_logic.honesty_bunker_buster_garrison_kill_ok(),
            "bunker-buster residual must kill garrisoned occupants"
        );
        assert!(
            game_logic.honesty_bunker_buster_damage_ok(),
            "bunker-buster residual must amplify bunker structure damage"
        );
        assert!(
            game_logic.bunker_buster_residual().occupants_killed >= 2,
            "both garrisoned infantry must die, got {}",
            game_logic.bunker_buster_residual().occupants_killed
        );

        // Occupants dead residual.
        for id in [inf_a, inf_b] {
            if let Some(u) = game_logic.find_object(id) {
                assert!(
                    !u.is_alive() || u.health.current <= 0.0 || u.status.destroyed,
                    "garrisoned occupant {id:?} must die to bunker buster"
                );
            }
        }
        // Bunker emptied + more damage than base 100.
        let bunker = game_logic.find_object(bunker_id).expect("bunker");
        assert_eq!(
            bunker.contained_units().len(),
            0,
            "bunker must be emptied of garrison"
        );
        let bunker_hp_after = bunker.health.current;
        let dealt = bunker_hp_before - bunker_hp_after;
        assert!(
            dealt > 100.0,
            "bunker must take amplified residual damage >100 (dealt={dealt}, before={bunker_hp_before}, after={bunker_hp_after})"
        );
    }

    /// Fail-closed: Stealth Fighter without Upgrade_AmericaBunkerBusters does not
    /// force-kill garrison (normal HP damage only).
    #[test]
    fn bunker_buster_residual_without_upgrade_does_not_bust() {
        use crate::game_logic::weapon_bootstrap::{
            ensure_host_weapon_store, STEALTH_JET_MISSILE_WEAPON,
        };

        ensure_host_weapon_store();

        let mut game_logic = GameLogic::new();
        ensure_test_infantry_template(&mut game_logic);
        ensure_test_garrison_template(&mut game_logic);

        let mut fighter_tpl = crate::game_logic::ThingTemplate::new("TestStealthFighter");
        fighter_tpl
            .add_kind_of(KindOf::Aircraft)
            .add_kind_of(KindOf::Selectable)
            .add_kind_of(KindOf::Attackable)
            .set_health(160.0)
            .set_primary_weapon_name(STEALTH_JET_MISSILE_WEAPON);
        game_logic
            .templates
            .insert("TestStealthFighter".to_string(), fighter_tpl);

        let fighter_id = game_logic
            .create_object("TestStealthFighter", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("fighter");
        let bunker_id = game_logic
            .create_object("TestBunker", Team::GLA, Vec3::new(50.0, 0.0, 0.0))
            .expect("bunker");
        let inf_id = game_logic
            .create_object("TestInfantry", Team::GLA, Vec3::new(51.0, 0.0, 0.0))
            .expect("inf");
        {
            let bunker = game_logic.find_object_mut(bunker_id).unwrap();
            assert!(bunker.add_occupant(inf_id));
        }
        {
            let u = game_logic.find_object_mut(inf_id).unwrap();
            u.contained_by = Some(bunker_id);
            u.ai_state = AIState::Garrisoned;
        }
        {
            let f = game_logic.find_object_mut(fighter_id).unwrap();
            f.attack_target(bunker_id);
            if let Some(w) = f.weapon.as_mut() {
                w.last_fire_time = -10.0;
                w.reload_time = 0.1;
                w.min_range = 0.0;
            }
        }

        game_logic.set_current_frame(20);
        game_logic.update_combat(&[fighter_id, bunker_id, inf_id], LOGIC_FRAME_TIMESTEP);

        assert!(
            !game_logic.honesty_bunker_buster_ok(),
            "fail-closed: no upgrade ⇒ no bunker-buster residual"
        );
        assert_eq!(
            game_logic.bunker_buster_residual().blasts,
            0,
            "without upgrade blasts must stay 0"
        );
        // Infantry may still be alive inside (normal structure HP damage only).
        let bunker = game_logic.find_object(bunker_id).expect("bunker");
        assert!(
            bunker.contained_units().contains(&inf_id)
                || game_logic
                    .find_object(inf_id)
                    .map(|u| u.is_alive())
                    .unwrap_or(false),
            "without bunker-buster upgrade garrison should not be force-cleared"
        );
    }

    /// Residual KILL_GARRISONED (MicrowaveTankBuildingClearer): kill floor(damage)
    /// garrisoned occupants without requiring bunker-buster upgrade.
    #[test]
    fn kill_garrisoned_residual_microwave_clears_occupants() {
        use crate::game_logic::weapon_bootstrap::{
            ensure_host_weapon_store, MICROWAVE_BUILDING_CLEARER_WEAPON,
        };

        ensure_host_weapon_store();

        let mut game_logic = GameLogic::new();
        ensure_test_infantry_template(&mut game_logic);
        ensure_test_garrison_template(&mut game_logic);

        let mut micro_tpl = crate::game_logic::ThingTemplate::new("TestMicrowave");
        micro_tpl
            .add_kind_of(KindOf::Vehicle)
            .add_kind_of(KindOf::Selectable)
            .add_kind_of(KindOf::Attackable)
            .set_health(300.0)
            .set_primary_weapon_name(MICROWAVE_BUILDING_CLEARER_WEAPON);
        game_logic
            .templates
            .insert("TestMicrowave".to_string(), micro_tpl);

        let micro_id = game_logic
            .create_object("TestMicrowave", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("microwave");
        let bunker_id = game_logic
            .create_object("TestBunker", Team::GLA, Vec3::new(40.0, 0.0, 0.0))
            .expect("bunker");
        let inf_a = game_logic
            .create_object("TestInfantry", Team::GLA, Vec3::new(41.0, 0.0, 0.0))
            .expect("inf_a");
        let inf_b = game_logic
            .create_object("TestInfantry", Team::GLA, Vec3::new(42.0, 0.0, 0.0))
            .expect("inf_b");
        {
            let bunker = game_logic.find_object_mut(bunker_id).unwrap();
            assert!(bunker.add_occupant(inf_a));
            assert!(bunker.add_occupant(inf_b));
        }
        for id in [inf_a, inf_b] {
            let u = game_logic.find_object_mut(id).unwrap();
            u.contained_by = Some(bunker_id);
            u.ai_state = AIState::Garrisoned;
        }

        let bunker_hp_before = game_logic
            .find_object(bunker_id)
            .map(|b| b.health.current)
            .unwrap_or(0.0);

        {
            let m = game_logic.find_object_mut(micro_id).unwrap();
            m.attack_target(bunker_id);
            if let Some(w) = m.weapon.as_mut() {
                w.last_fire_time = -10.0;
                w.reload_time = 0.1;
                w.min_range = 0.0;
                w.damage = 1.0; // KILL_GARRISONED amount = 1 occupant
            }
        }

        game_logic.set_current_frame(20);
        game_logic.update_combat(&[micro_id, bunker_id, inf_a, inf_b], LOGIC_FRAME_TIMESTEP);

        assert!(
            game_logic.honesty_kill_garrisoned_ok(),
            "KILL_GARRISONED residual honesty"
        );
        assert_eq!(
            game_logic.bunker_buster_residual().occupants_killed,
            1,
            "damage=1 must kill exactly one garrisoned unit"
        );

        // Structure HP preserved (C++ KillGarrisoned does not apply body HP).
        let bunker_hp_after = game_logic
            .find_object(bunker_id)
            .map(|b| b.health.current)
            .unwrap_or(0.0);
        assert!(
            (bunker_hp_after - bunker_hp_before).abs() < 0.01,
            "KILL_GARRISONED residual must not damage bunker HP (before={bunker_hp_before}, after={bunker_hp_after})"
        );
        let remaining = game_logic
            .find_object(bunker_id)
            .map(|b| b.contained_units().len())
            .unwrap_or(0);
        assert_eq!(remaining, 1, "one occupant must remain after single clear");
    }

    /// Residual: Microwave tank attacking enemy structure applies DISABLED_SUBDUED
    /// (production stop residual) while cooking; clears when attack stops.
    #[test]
    fn microwave_tank_residual_disables_enemy_structure() {
        use crate::game_logic::host_microwave::{is_microwave_tank, HOST_MICROWAVE_DISABLE_RANGE};
        use crate::game_logic::weapon_bootstrap::{
            ensure_host_weapon_store, MICROWAVE_BUILDING_CLEARER_WEAPON,
        };

        ensure_host_weapon_store();

        let mut game_logic = GameLogic::new();
        ensure_test_garrison_template(&mut game_logic);

        let mut micro_tpl = crate::game_logic::ThingTemplate::new("AmericaTankMicrowave");
        micro_tpl
            .add_kind_of(KindOf::Vehicle)
            .add_kind_of(KindOf::Selectable)
            .add_kind_of(KindOf::Attackable)
            .set_health(480.0)
            .set_primary_weapon_name(MICROWAVE_BUILDING_CLEARER_WEAPON);
        game_logic
            .templates
            .insert("AmericaTankMicrowave".to_string(), micro_tpl);

        let mut barracks_tpl = crate::game_logic::ThingTemplate::new("TestBarracks");
        barracks_tpl
            .add_kind_of(KindOf::Structure)
            .add_kind_of(KindOf::Selectable)
            .add_kind_of(KindOf::FSBarracks)
            .set_health(1000.0);
        game_logic
            .templates
            .insert("TestBarracks".to_string(), barracks_tpl);

        let micro_id = game_logic
            .create_object("AmericaTankMicrowave", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("microwave");
        let barracks_id = game_logic
            .create_object(
                "TestBarracks",
                Team::GLA,
                Vec3::new(HOST_MICROWAVE_DISABLE_RANGE * 0.4, 0.0, 0.0),
            )
            .expect("barracks");

        {
            let m = game_logic.find_object(micro_id).expect("microwave");
            assert!(
                is_microwave_tank(&m.template_name),
                "AmericaTankMicrowave must classify as microwave residual"
            );
        }
        {
            let b = game_logic.find_object_mut(barracks_id).unwrap();
            // Ensure structure residual + constructed.
            b.object_type = ObjectType::Building;
            b.construction_percent = 1.0;
            b.status.under_construction = false;
        }

        assert!(!game_logic.honesty_microwave_disable_ok());
        assert!(
            !game_logic
                .find_object(barracks_id)
                .map(|b| b.is_subdued_disabled())
                .unwrap_or(true),
            "structure starts not subdued"
        );

        // Microwave cooks the barracks.
        {
            let m = game_logic.find_object_mut(micro_id).unwrap();
            m.attack_target(barracks_id);
        }

        game_logic.frame = 1;
        game_logic.update_microwave_disable();

        assert!(
            game_logic.honesty_microwave_disable_ok(),
            "microwave disable residual honesty"
        );
        assert!(
            game_logic.honesty_microwave_ok(),
            "microwave host path honesty"
        );
        {
            let b = game_logic.find_object(barracks_id).expect("barracks");
            assert!(
                b.is_subdued_disabled(),
                "structure must be DISABLED_SUBDUED while cooked"
            );
            assert!(
                b.is_disabled(),
                "subdued structure must count as is_disabled (production stop residual)"
            );
        }

        // Ally structure residual-skip: USA barracks next to USA microwave.
        let mut ally_tpl = crate::game_logic::ThingTemplate::new("TestAllyBarracks");
        ally_tpl.add_kind_of(KindOf::Structure).set_health(1000.0);
        game_logic
            .templates
            .insert("TestAllyBarracks".to_string(), ally_tpl);
        let ally_id = game_logic
            .create_object("TestAllyBarracks", Team::USA, Vec3::new(30.0, 0.0, 0.0))
            .expect("ally barracks");
        {
            let a = game_logic.find_object_mut(ally_id).unwrap();
            a.object_type = ObjectType::Building;
            a.construction_percent = 1.0;
            a.status.under_construction = false;
            // Force cook attempt on ally (should not disable).
        }
        {
            let m = game_logic.find_object_mut(micro_id).unwrap();
            m.attack_target(ally_id);
        }
        game_logic.frame = 2;
        game_logic.update_microwave_disable();
        assert!(
            !game_logic
                .find_object(ally_id)
                .map(|a| a.is_subdued_disabled())
                .unwrap_or(true),
            "fail-closed: ally structure must not be microwave-disabled"
        );
        // Enemy barracks no longer targeted — subdued must clear.
        assert!(
            !game_logic
                .find_object(barracks_id)
                .map(|b| b.is_subdued_disabled())
                .unwrap_or(true),
            "DISABLED_SUBDUED must clear when microwave stops cooking"
        );
    }

    /// Residual: non-microwave unit does not disable structures via microwave residual.
    #[test]
    fn microwave_tank_residual_skips_non_microwave() {
        let mut game_logic = GameLogic::new();
        ensure_test_tank_template(&mut game_logic);

        let mut barracks_tpl = crate::game_logic::ThingTemplate::new("TestBarracks");
        barracks_tpl
            .add_kind_of(KindOf::Structure)
            .set_health(1000.0);
        game_logic
            .templates
            .insert("TestBarracks".to_string(), barracks_tpl);

        let tank_id = game_logic
            .create_object("TestTank", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("tank");
        let barracks_id = game_logic
            .create_object("TestBarracks", Team::GLA, Vec3::new(40.0, 0.0, 0.0))
            .expect("barracks");
        {
            let b = game_logic.find_object_mut(barracks_id).unwrap();
            b.object_type = ObjectType::Building;
            b.construction_percent = 1.0;
            b.status.under_construction = false;
        }
        {
            let t = game_logic.find_object_mut(tank_id).unwrap();
            t.attack_target(barracks_id);
        }

        game_logic.frame = 1;
        game_logic.update_microwave_disable();
        assert!(
            !game_logic.honesty_microwave_disable_ok(),
            "fail-closed: ordinary tank must not microwave-disable"
        );
        assert!(!game_logic
            .find_object(barracks_id)
            .map(|b| b.is_subdued_disabled())
            .unwrap_or(true));
    }

    /// Residual: King Raptor (AirF_AmericaJetRaptor) dual PDL intercepts missiles.
    #[test]
    fn king_raptor_residual_laser_intercepts_missile() {
        use crate::game_logic::host_point_defense::{
            is_king_raptor_carrier, is_point_defense_carrier, KING_RAPTOR_PDL_DELAY_FRAMES,
            KING_RAPTOR_PDL_FIRE_RANGE,
        };

        let mut game_logic = GameLogic::new();

        let mut raptor_tpl = crate::game_logic::ThingTemplate::new("AirF_AmericaJetRaptor");
        raptor_tpl
            .add_kind_of(KindOf::Vehicle)
            .add_kind_of(KindOf::Selectable)
            .add_kind_of(KindOf::Attackable)
            .set_health(240.0)
            .set_primary_weapon_name(super::weapon_bootstrap::RANGER_PRIMARY_WEAPON);
        game_logic
            .templates
            .insert("AirF_AmericaJetRaptor".to_string(), raptor_tpl);

        let mut missile_tpl = crate::game_logic::ThingTemplate::new("TestMissile");
        missile_tpl
            .add_kind_of(KindOf::Projectile)
            .add_kind_of(KindOf::Attackable)
            .set_health(50.0);
        game_logic
            .templates
            .insert("TestMissile".to_string(), missile_tpl);

        let raptor_id = game_logic
            .create_object("AirF_AmericaJetRaptor", Team::USA, Vec3::new(0.0, 0.0, 0.0))
            .expect("king raptor");
        let missile_id = game_logic
            .create_object(
                "TestMissile",
                Team::GLA,
                Vec3::new(KING_RAPTOR_PDL_FIRE_RANGE * 0.5, 0.0, 0.0),
            )
            .expect("missile");

        {
            let r = game_logic.find_object(raptor_id).expect("king raptor");
            assert!(
                is_king_raptor_carrier(&r.template_name),
                "AirF_AmericaJetRaptor must classify as King Raptor residual"
            );
            assert!(
                is_point_defense_carrier(&r.template_name),
                "King Raptor must be a PDL carrier residual"
            );
        }
        assert!(!game_logic.honesty_point_defense_intercept_ok());

        game_logic.frame = 1;
        game_logic.update_point_defense_intercept();

        assert!(
            game_logic.honesty_point_defense_intercept_ok(),
            "King Raptor PDL residual honesty must record intercept"
        );
        assert!(
            game_logic.point_defense_residual_intercepts() > 0,
            "intercept counter must advance"
        );
        if let Some(m) = game_logic.find_object(missile_id) {
            assert!(
                !m.is_alive() || m.health.current <= 0.0,
                "missile must be dead after King Raptor laser intercept (hp={})",
                m.health.current
            );
        }

        // Reload residual: dual-laser residual delay (4 frames).
        let intercepts_after_first = game_logic.point_defense_residual_intercepts();
        game_logic.frame = 2;
        let _missile2 = game_logic
            .create_object("TestMissile", Team::China, Vec3::new(20.0, 0.0, 0.0))
            .expect("missile2");
        game_logic.update_point_defense_intercept();
        assert_eq!(
            game_logic.point_defense_residual_intercepts(),
            intercepts_after_first,
            "King Raptor PDL must respect residual dual-laser delay"
        );

        game_logic.frame = 1 + KING_RAPTOR_PDL_DELAY_FRAMES;
        game_logic.update_point_defense_intercept();
        assert!(
            game_logic.point_defense_residual_intercepts() > intercepts_after_first,
            "King Raptor PDL must fire again after residual delay"
        );
    }

