            assert!(!is_king_raptor_template(&r.template_name));
            let prim = r.weapon.as_ref().expect("missile");
            assert!((prim.damage - RAPTOR_DAMAGE).abs() < 0.01);
            assert!((prim.range - RAPTOR_RANGE).abs() < 1.0);
